CREATE OR REPLACE FUNCTION fpb_get_loan_installment (as_conno char) RETURNS integer AS $body$
DECLARE

li_install integer;

BEGIN

  select  loan_installment_amount
  into STRICT li_install
  from sc_lon_m_contract
  where loan_contract_no = as_conno;

  return li_install;

exception when others then return 0;
end;
